	private static final class ExtensionPlan implements SlotPlan {
		private final SlotPlan arg;
		private final CopyBinding[] copies;
		private final long producedMask;

		private ExtensionPlan(SlotPlan arg, CopyBinding[] copies) {
			this.arg = arg;
			this.copies = copies;
			long mask = arg.producedMask();
			for (CopyBinding copy : copies) {
				mask |= 1L << copy.targetSlot;
			}
			this.producedMask = mask;
		}

		@Override
		public RowCursor open(RowState row) throws IOException {
			return new ExtensionCursor(arg.open(row), copies, row);
		}

		@Override
		public long producedMask() {
			return producedMask;
		}
	}

	private static final class ExtensionCursor implements RowCursor {
		private final RowCursor arg;
		private final CopyBinding[] copies;
		private final RowState row;
		private int activeMark = -1;

		private ExtensionCursor(RowCursor arg, CopyBinding[] copies, RowState row) {
			this.arg = arg;
			this.copies = copies;
			this.row = row;
		}

		@Override
		public boolean next() throws IOException {
			release();
			while (arg.next()) {
				int mark = row.mark();
				boolean ok = true;
				for (CopyBinding copy : copies) {
					long id = copy.value(row);
					if (id != UNKNOWN && !row.bind(copy.targetSlot, id)) {
						ok = false;
						break;
					}
				}
				if (ok) {
					activeMark = mark;
					return true;
				}
				row.rollback(mark);
			}
			return false;
		}

		@Override
		public void close() {
			release();
			arg.close();
		}

		private void release() {
			if (activeMark >= 0) {
				row.rollback(activeMark);
				activeMark = -1;
			}
		}
	}

